import React, { useState, useEffect } from 'react';
import { MapContainer, TileLayer, Marker, Popup, Circle } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';
import axios from 'axios';

// Fix for default marker icons in Leaflet
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon-2x.png',
  iconUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon.png',
  shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-shadow.png',
});

const MapView = () => {
  const [vendors, setVendors] = useState([]);
  const solapurCenter = [17.6599, 75.9064];

  useEffect(() => {
    const fetchVendors = async () => {
      try {
        const response = await axios.get('http://10.113.178.31:8080/api/vendors');
        setVendors(response.data.filter(v => v.status === 'APPROVED'));
      } catch (err) {
        console.error('Error fetching vendors for map', err);
      }
    };
    fetchVendors();
  }, []);

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-gray-800">Live Vending Map</h1>
        <p className="text-gray-500 text-sm">Real-time location of approved street vendors in Solapur</p>
      </div>

      <div className="bg-white p-4 rounded-xl shadow-md border h-[600px] overflow-hidden">
        <MapContainer center={solapurCenter} zoom={13} style={{ height: '100%', width: '100%' }}>
          <TileLayer
            attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
            url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
          />

          {vendors.map(vendor => (
            <React.Fragment key={vendor.id}>
              <Marker position={[vendor.latitude, vendor.longitude]}>
                <Popup>
                  <div className="p-2">
                    <p className="font-bold text-smc-blue">{vendor.name}</p>
                    <p className="text-xs text-gray-500">{vendor.category}</p>
                    <p className="text-[10px] mt-1">{vendor.vendorId}</p>
                  </div>
                </Popup>
              </Marker>
              <Circle 
                center={[vendor.latitude, vendor.longitude]} 
                radius={50} 
                pathOptions={{ color: '#1e40af', fillColor: '#1e40af', fillOpacity: 0.1 }} 
              />
            </React.Fragment>
          ))}
        </MapContainer>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="flex items-center gap-2 text-sm text-gray-600 bg-blue-50 p-3 rounded-lg border border-blue-100">
          <div className="w-4 h-4 rounded-full bg-blue-600"></div>
          <span>Blue Marker: Approved Vendor</span>
        </div>
        <div className="flex items-center gap-2 text-sm text-gray-600 bg-blue-50 p-3 rounded-lg border border-blue-100">
          <div className="w-8 h-8 rounded-full bg-blue-600 opacity-20 border border-blue-600"></div>
          <span>Blue Circle: 50m Legal Zone</span>
        </div>
      </div>
    </div>
  );
};

export default MapView;
